  2	import { type FC, type FormEvent, useCallback, useEffect, useState } from 'react';
  3	import { usePlanMigration } from 'src/plans/hooks/usePlanMigration';
  4	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
  5	
  6	import ModalForm from '@components/ModalForm/ModalForm';
  7	import type { V1beta1Plan } from '@kubev2v/types';
  8	import {
  9	  ButtonVariant,
 10	  DatePicker,
 11	  InputGroup,
 12	  Stack,
 13	  StackItem,
 14	  TimePicker,
 15	  yyyyMMddFormat,
 16	} from '@patternfly/react-core';
 17	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 18	import { getName } from '@utils/crds/common/selectors';
 19	
 20	import { formatDateTo12Hours, patchMigrationCutover } from './utils/utils';
 21	
 22	import './PlanCutoverMigrationModal.scss';
 23	
 24	type PlanCutoverMigrationModalProps = {
 25	  plan: V1beta1Plan;
 26	};
 27	
 28	const PlanCutoverMigrationModal: FC<PlanCutoverMigrationModalProps> = ({ plan }) => {
 29	  const { t } = useForkliftTranslation();
 30	  const { trackEvent } = useForkliftAnalytics();
 31	  const [cutoverDate, setCutoverDate] = useState<string>();
 32	  const [time, setTime] = useState<string>();
 33	  const [isDateValid, setIsDateValid] = useState<boolean>(true);
 34	  const [isTimeValid, setIsTimeValid] = useState<boolean>(true);
 35	
 36	  const [lastMigration] = usePlanMigration(plan);
 37	
 38	  useEffect(() => {
 39	    const migrationCutoverDate = lastMigration?.spec?.cutover ?? new Date().toISOString();
 40	
 41	    setCutoverDate(migrationCutoverDate);
 42	    setTime(formatDateTo12Hours(new Date(migrationCutoverDate)));
 43	  }, [lastMigration]);
 44	
 45	  const onDateChange: (event: FormEvent<HTMLInputElement>, value: string, date?: Date) => void = (
 46	    _event,
 47	    value,
 48	    date,
 49	  ) => {
 50	    setIsDateValid(Boolean(date));
 51	    if (!date) return;
 52	
 53	    const updatedFromDate = cutoverDate ? new Date(cutoverDate) : new Date();
 54	
 55	    const [year, month, day] = value.split('-').map((num: string) => parseInt(num, 10));
 56	
 57	    updatedFromDate.setFullYear(year);
 58	    updatedFromDate.setMonth(month - 1);
 59	    updatedFromDate.setDate(day);
 60	
 61	    setCutoverDate(updatedFromDate.toISOString());
 62	  };
 63	
 64	  // eslint-disable-next-line @typescript-eslint/max-params
 65	  const onTimeChange: (
 66	    event: FormEvent<HTMLInputElement>,
 67	    timeInput: string,
 68	    hour?: number,
 69	    minute?: number,
 70	    seconds?: number,
 71	    timeValid?: boolean,
 72	    // eslint-disable-next-line @typescript-eslint/max-params
 73	  ) => void = (_event, timeInput, hour, minute, _seconds, timeValid) => {
 74	    setTime(timeInput);
 75	    setIsTimeValid(Boolean(timeValid) && Boolean(timeInput));
 76	
 77	    if (!timeValid) return;
 78	
 79	    const updatedFromDate = cutoverDate ? new Date(cutoverDate) : new Date();
 80	
 81	    updatedFromDate.setHours(hour!);
 82	    updatedFromDate.setMinutes(minute!);
 83	
 84	    setCutoverDate(updatedFromDate.toISOString());
 85	  };
 86	
 87	  const onCutover = useCallback(
 88	    async () => patchMigrationCutover(lastMigration, cutoverDate, trackEvent),
 89	    [cutoverDate, lastMigration, trackEvent],
 90	  );
 91	
 92	  const onDeleteCutover = useCallback(
 93	    async () => patchMigrationCutover(lastMigration, undefined, trackEvent),
 94	    [lastMigration, trackEvent],
 95	  );
 96	
 97	  return (
 98	    <ModalForm
 99	      title={lastMigration?.spec?.cutover ? t('Edit cutover') : t('Schedule cutover')}
100	      onConfirm={onCutover}
101	      confirmLabel={t('Set cutover')}
102	      additionalAction={{
103	        children: t('Remove cutover'),
104	        onClick: onDeleteCutover,
105	        variant: ButtonVariant.secondary,
106	      }}
107	      isDisabled={!isTimeValid || !isDateValid}
108	    >
109	      <ForkliftTrans>
110	        <Stack hasGutter>
111	          <StackItem>
112	            Schedule the cutover for migration{' '}
113	            <strong className="co-break-word">{getName(plan)}</strong>?
114	          </StackItem>
115	          <StackItem>
116	            You can schedule cutover for now or a future date and time. VMs included in the
117	            migration plan will be shut down when cutover starts.
118	          </StackItem>
119	        </Stack>
120	      </ForkliftTrans>
121	      <InputGroup className="forklift-plan-cutover-migration-inputgroup">
122	        <DatePicker
123	          onChange={onDateChange}
124	          aria-label="Cutover date"
125	          placeholder="YYYY-MM-DD"
126	          appendTo={document.body}
127	          value={yyyyMMddFormat(cutoverDate ? new Date(cutoverDate) : new Date())}
128	        />
129	        <TimePicker
130	          aria-label="Cutover time"
131	          onChange={onTimeChange}
132	          menuAppendTo={document.body}
133	          time={time}
134	        />
135	      </InputGroup>
136	    </ModalForm>
137	  );
138	};
139	
140	export default PlanCutoverMigrationModal;

